  "agent": "claude_code",
  "sandbox": "local",
  "workflow_id": "rabbitmq-security-upgrade-v2-01",
  "stage_total": 8,
  "stages": [
    {
      "id": "stage_01",
      "service": "rabbitmq",
      "case_name": "classic_queue",
      "param_overrides": {
        "cluster_prefix": "rabbitmq"
      }
    },
    {
      "id": "stage_02",
      "service": "rabbitmq",
      "case_name": "manual_user_permission",
      "param_overrides": {
        "cluster_prefix": "rabbitmq"
      }
    },
    {
      "id": "stage_03",
      "service": "rabbitmq",
      "case_name": "manual_policy_sync",
      "param_overrides": {
        "cluster_prefix": "rabbitmq"
      }
    },
    {
      "id": "stage_04",
      "service": "rabbitmq",
      "case_name": "manual_monitoring",
      "param_overrides": {
        "cluster_prefix": "rabbitmq"
      }
    },
    {
      "id": "stage_05",
      "service": "rabbitmq",
      "case_name": "manual_skip_upgrade",
      "param_overrides": {
        "cluster_prefix": "rabbitmq",
        "from_version": "3.12",
        "to_version": "3.12"
      }
    },
    {
      "id": "stage_06",
      "service": "rabbitmq",
      "case_name": "manual_policy_sync",
      "param_overrides": {
        "cluster_prefix": "rabbitmq"
